import{_ as p,c as t}from"./app.90a21e26.js";const r={},s=t('<h1 id="_52-\u8BB2-\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u53EF\u6269\u5C55\u6027\u67B6\u6784\u8BBE\u8BA1" tabindex="-1"><a class="header-anchor" href="#_52-\u8BB2-\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u53EF\u6269\u5C55\u6027\u67B6\u6784\u8BBE\u8BA1" aria-hidden="true">#</a> 52 \u8BB2\uFF1A\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u53EF\u6269\u5C55\u6027\u67B6\u6784\u8BBE\u8BA1</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\u3002\u4ECA\u5929\u6211\u548C\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u662F\uFF1A\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u53EF\u6269\u5C55\u6027\u67B6\u6784\u8BBE\u8BA1\u3002</p><p>\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4ECE\u53EF\u4F38\u7F29\u6027\u548C\u53EF\u6269\u5C55\u6027\u5BF9\u5E94\u7684\u82F1\u6587\u672F\u8BED\u7684\u89D2\u5EA6\uFF0C\u548C\u4F60\u5206\u4EAB\u4E86\u8FD9\u4E24\u4E2A\u6982\u5FF5\u7684\u5DEE\u5F02\uFF0C\u5E76\u4E14\u548C\u4F60\u8BE6\u7EC6\u4ECB\u7ECD\u4E86\u7F51\u7AD9\u7684\u53EF\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1\u4E3B\u8981\u5305\u62EC\u7684\u5185\u5BB9\uFF0C\u4EE5\u53CA\u4ECE\u6D4B\u8BD5\u4EBA\u5458\u7684\u89C6\u89D2\u9700\u8981\u5173\u6CE8\u54EA\u4E9B\u70B9\u8FDB\u884C\u9488\u5BF9\u6027\u7684\u6D4B\u8BD5\u3002</p><p>\u6240\u4EE5\uFF0C\u5728\u4ECA\u5929\u8FD9\u7BC7\u6587\u7AE0\uFF0C\u4E5F\u662F\u8FD9\u4E2A\u4E13\u680F\u6700\u540E\u4E00\u7BC7\u6B63\u6587\u4E2D\uFF0C\u6211\u4F1A\u518D\u548C\u4F60\u8BE6\u7EC6\u8BA8\u8BBA\u7F51\u7AD9\u7684\u53EF\u6269\u5C55\u6027\uFF08Extensibility\uFF09\u67B6\u6784\u8BBE\u8BA1\u3002\u8FD9\u91CC\uFF0C\u6211\u5148\u5E26\u4F60\u4E00\u8D77\u56DE\u987E\u4E00\u4E0B\u53EF\u6269\u5C55\u6027\u7684\u5B9A\u4E49\uFF1A</p><p>\u53EF\u6269\u5C55\u6027\uFF0C\u6307\u7684\u662F\u7F51\u7AD9\u7684\u67B6\u6784\u8BBE\u8BA1\u80FD\u591F\u5FEB\u901F\u9002\u5E94\u9700\u6C42\u7684\u53D8\u5316\uFF0C\u5F53\u9700\u8981\u589E\u52A0\u65B0\u7684\u529F\u80FD\u5B9E\u73B0\u65F6\uFF0C\u5BF9\u539F\u6709\u67B6\u6784\u4E0D\u9700\u8981\u505A\u4FEE\u6539\u6216\u8005\u505A\u5F88\u5C11\u7684\u4FEE\u6539\u5C31\u80FD\u591F\u5FEB\u901F\u5B9E\u73B0\u65B0\u7684\u4E1A\u52A1\u9700\u6C42\u3002</p><p>\u4ECE\u8FD9\u4E2A\u5B9A\u4E49\u4E2D\uFF0C\u6211\u4EEC\u5F88\u5BB9\u6613\u5C31\u53EF\u4EE5\u5F97\u51FA\u8861\u91CF\u7F51\u7AD9\u53EF\u6269\u5C55\u6027\u8BBE\u8BA1\u4F18\u79C0\u4E0E\u5426\u7684\u4E3B\u8981\u6807\u51C6\uFF0C\u5C31\u662F\u589E\u52A0\u65B0\u529F\u80FD\u7684\u65F6\u5019\u5BF9\u539F\u6709\u7CFB\u7EDF\u7684\u5F71\u54CD\u662F\u5426\u8DB3\u591F\u5C0F\u3002</p><p>\u5F53\u4ECA\u7684\u5546\u4E1A\u73AF\u5883\u51B3\u5B9A\u4E86\u7F51\u7AD9\u65B0\u529F\u80FD\u5F00\u53D1\u4E0E\u4E0A\u7EBF\u7684\u65F6\u95F4\u5468\u671F\u5FC5\u987B\u975E\u5E38\u77ED\uFF0C\u5982\u679C\u6BCF\u6B21\u6DFB\u52A0\u65B0\u529F\u80FD\uFF0C\u90FD\u9700\u8981\u5BF9\u539F\u6709\u7CFB\u7EDF\u8FDB\u884C\u5927\u91CF\u4FEE\u6539\uFF0C\u4ECE\u800C\u8FD8\u4F1A\u7275\u8FDE\u51FA\u66F4\u591A\u6D4B\u8BD5\u5DE5\u4F5C\u7684\u8BDD\uFF0C\u90A3\u4E48\u4F60\u7684\u7ADE\u4E89\u529B\u5C31\u4F1A\u88AB\u5927\u6253\u6298\u6263\uFF0C\u7528\u4E00\u4E2A\u4E0D\u592A\u6070\u5F53\u7684\u6BD4\u55BB\u5C31\u662F\u76F4\u63A5\u201C\u8F93\u5728\u4E86\u8D77\u8DD1\u7EBF\u4E0A\u201D\u3002</p><p>\u5176\u5B9E\uFF0C\u4F60\u6211\u90FD\u6E05\u695A\u6DFB\u52A0\u65B0\u529F\u80FD\u65F6\u5FC5\u987B\u8981\u5BF9\u7CFB\u7EDF\u8FDB\u884C\u5927\u5E45\u5EA6\u4FEE\u6539\u7684\u539F\u56E0\u662F\uFF0C\u7CFB\u7EDF\u67B6\u6784\u8BBE\u8BA1\u4E0A\u7684\u8026\u5408\u6027\u3002\u90A3\u4E48\uFF0C\u6709\u4EC0\u4E48\u201C\u597D\u7684\u201D\u67B6\u6784\u8BBE\u8BA1\u65B9\u6848\u53EF\u4EE5\u4F7F\u5F97\u6211\u4EEC\u6DFB\u52A0\u65B0\u529F\u80FD\u7684\u65F6\u5019\uFF0C\u53EA\u9700\u5BF9\u539F\u6709\u7CFB\u7EDF\u505A\u5C11\u91CF\u4FEE\u6539\uFF0C\u751A\u81F3\u5B8C\u5168\u4E0D\u9700\u8981\u4FEE\u6539\u5417\uFF1F</p><p>\u548B\u4E00\u542C\u8D77\u6765\uFF0C\u8FD9\u5C31\u50CF\u201C\u53C8\u8981\u9A6C\u513F\u8DD1\uFF0C\u53C8\u8981\u9A6C\u513F\u4E0D\u5403\u8349\u201D\u3002\u4F46\uFF0C\u5176\u5B9E\u4E0D\u662F\u7684\u3002\u6211\u4EEC\u5F80\u5F80\u53EF\u4EE5\u901A\u8FC7\u67B6\u6784\u4E0A\u7684\u8BBE\u8BA1\u4F18\u5316\u6765\u8FBE\u5230\u4E8B\u534A\u529F\u500D\u7684\u6548\u679C\u3002</p><p>\u4E3A\u4E86\u5E2E\u52A9\u4F60\u7406\u89E3\u53EF\u6269\u5C55\u6027\uFF0C\u6211\u5148\u548C\u4F60\u5206\u4EAB\u4E00\u4E2A\u6848\u4F8B\u3002</p><p><strong>\u7F51\u7AD9\u53EF\u6269\u5C55\u6027\u67B6\u6784\u8BBE\u8BA1\u7684\u6848\u4F8B</strong></p><p>\u5047\u8BBE\u4F60\u73B0\u5728\u4E3A\u4E86\u5B9E\u65F6\u76D1\u63A7\u670D\u52A1\u5668\u7684\u5065\u5EB7\u72B6\u6001\uFF0C\u9700\u8981\u4E3A\u7F51\u7AD9\u6DFB\u52A0\u4E00\u4E2A\u5B9E\u65F6\u6536\u96C6\u670D\u52A1\u5668\u7AEF\u76D1\u63A7\u6307\u6807\u7684\u529F\u80FD\uFF0C\u6B64\u65F6\u6700\u76F4\u63A5\u7684\u65B9\u6848\u5C31\u662F\u7528\u4EE3\u7801\u53BB\u5B9E\u73B0\u5BF9\u6BCF\u4E00\u4E2A\u76D1\u63A7\u6307\u6807\u7684\u6536\u96C6\uFF0C\u7136\u540E\u5C06\u6240\u6709\u7684\u8FD9\u4E9B\u4EE3\u7801\u96C6\u6210\u5728\u4E00\u8D77\u5F62\u6210\u4E00\u4E2A\u53EF\u6267\u884C\u7A0B\u5E8F\u8FD0\u884C\u5728\u670D\u52A1\u5668\u7AEF\u540E\u53F0\u3002</p><p>\u8FD9\u6837\u7684\u8BBE\u8BA1\u56FA\u7136\u7B80\u5355\u76F4\u63A5\uFF0C\u800C\u4E14\u4E5F\u80FD\u5B9E\u73B0\u6240\u6709\u7684\u529F\u80FD\u9700\u6C42\uFF08\u6536\u96C6\u5404\u79CD\u76D1\u63A7\u6307\u6807\uFF09\uFF0C\u4F46\u662F\u5F53\u4F60\u9700\u8981\u6536\u96C6\u4E00\u4E2A\u65B0\u7684\u76D1\u63A7\u6307\u6807\u65F6\uFF0C\u5C31\u4E0D\u5F97\u4E0D\u66F4\u65B0\u6574\u4E2A\u53EF\u6267\u884C\u7A0B\u5E8F\u4E86\u3002\u5982\u679C\u4F60\u9700\u8981\u7ECF\u5E38\u6DFB\u52A0\u65B0\u7684\u76D1\u63A7\u6307\u6807\u7684\u8BDD\uFF0C\u90A3\u4E48\u8FD9\u6837\u7684\u8BBE\u8BA1\u5C31\u4E0D\u80FD\u6EE1\u8DB3\u53EF\u6269\u5C55\u6027\u7684\u8981\u6C42\u4E86\u3002</p><p><strong>\u6211\u4EEC\u5E0C\u671B\u7684\u662F\uFF0C\u5F53\u589E\u52A0\u65B0\u7684\u76D1\u63A7\u6307\u6807\u7684\u65F6\u5019\uFF0C\u539F\u6709\u7684\u7CFB\u7EDF\u4E0D\u9700\u8981\u505A\u4EFB\u4F55\u4FEE\u6539\uFF0C\u751A\u81F3\u53EF\u4EE5\u505A\u5230\u5B9E\u65F6\u6DFB\u52A0\u5168\u65B0\u7684\u76D1\u63A7\u6307\u6807</strong>\u3002\u4E3A\u4E86\u8FBE\u5230\u8FD9\u4E2A\u76EE\u7684\uFF0C\u73B0\u6709\u7684\u5176\u4ED6\u65B9\u6848\u90FD\u4E0D\u80FD\u6EE1\u8DB3\u6216\u8005\u4E0D\u5BB9\u6613\u6EE1\u8DB3\u8FD9\u4E2A\u8981\u6C42\uFF0C\u6240\u4EE5\u6211\u4EEC\u5C31\u5FC5\u987B\u8981\u5728\u67B6\u6784\u8BBE\u8BA1\u4E0A\u505A\u4E9B\u6587\u7AE0\u4E86\u3002</p><p>\u6211\u4EEC\u53EF\u4EE5\u628A\u5BF9\u6BCF\u4E00\u4E2A\u76D1\u63A7\u6307\u6807\u7684\u4EE3\u7801\u5B9E\u73B0\uFF0C\u76F4\u63A5\u6253\u5305\u6210\u4E00\u4E2A\u4E2A\u7684\u53EF\u6267\u884C\u76D1\u63A7\u5B50\u7A0B\u5E8F\uFF0C\u6BD4\u5982\u6536\u96C6 CPU \u4F7F\u7528\u7387\u7684\u7A0B\u5E8F A\u3001\u6536\u96C6\u5185\u5B58\u4F7F\u7528\u7387\u7684\u7A0B\u5E8F B \u7B49\uFF0C\u7136\u540E\u8FD0\u884C\u5728\u670D\u52A1\u5668\u540E\u53F0\u7684\u76D1\u63A7\u4E3B\u7A0B\u5E8F\u901A\u8FC7\u8C03\u7528\u8FD9\u4E9B\u5B50\u7A0B\u5E8F\uFF0C\u6BD4\u5982\u7A0B\u5E8F A \u548C B\uFF0C\u6765\u5B9E\u73B0\u6240\u6709\u7684\u76D1\u63A7\u9700\u6C42\u3002</p><p>\u8FD9\u65F6\uFF0C\u518D\u589E\u52A0\u65B0\u7684\u76D1\u63A7\u6307\u6807\u65F6\uFF0C\u539F\u6709\u7CFB\u7EDF\u5C31\u4E0D\u9700\u8981\u505A\u4EFB\u4F55\u6539\u52A8\uFF0C\u53EA\u9700\u8981\u72EC\u7ACB\u5B9E\u73B0\u65B0\u7684\u76D1\u63A7\u5B50\u7A0B\u5E8F\uFF0C\u7136\u540E\u4EE5\u914D\u7F6E\u6587\u4EF6\u7684\u5F62\u5F0F\u201C\u544A\u8BC9\u201D\u4E3B\u7A0B\u5E8F\u65B0\u6DFB\u52A0\u7684\u76D1\u63A7\u5B50\u7A0B\u5E8F\u7684\u8DEF\u5F84\u5373\u53EF\u3002\u8FD9\u4E5F\u5C31\u5B9E\u73B0\u4E86\u7CFB\u7EDF\u7684\u53EF\u6269\u5C55\u6027\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u4EEC\u518D\u4E00\u8D77\u56DE\u5230\u7F51\u7AD9\u7684\u53EF\u6269\u5C55\u6027\u8BBE\u8BA1\u4E0A\u6765\u3002\u5176\u5B9E\uFF0C<strong>\u63D0\u5347\u7F51\u7AD9\u53EF\u6269\u5C55\u6027\u6027\u7684\u6838\u5FC3\uFF0C\u5C31\u662F\u964D\u4F4E\u7CFB\u7EDF\u5404\u4E2A\u6A21\u5757\u548C\u7EC4\u4EF6\u4E4B\u95F4\u7684\u8026\u5408</strong>\u3002\u8026\u5408\u7A0B\u5EA6\u8D8A\u4F4E\uFF0C\u5404\u4E2A\u6A21\u5757\u548C\u7EC4\u4EF6\u7684\u590D\u7528\u53EF\u80FD\u6027\u5C31\u8D8A\u5927\uFF0C\u7CFB\u7EDF\u7684\u53EF\u6269\u5C55\u6027\u4E5F\u4F1A\u8D8A\u597D\u3002</p><p>\u4ECE\u73B0\u5728\u6765\u770B\uFF0C\u5B9E\u73B0\u7F51\u7AD9\u53EF\u6269\u5C55\u6027\u67B6\u6784\u7684\u4E3B\u8981\u6280\u672F\u624B\u6BB5\u5305\u62EC\u4E8B\u4EF6\u9A71\u52A8\u67B6\u6784\u548C\u5FAE\u670D\u52A1\u67B6\u6784\u3002</p><p>\u5FAE\u670D\u52A1\u67B6\u6784\u4ECE\u6839\u672C\u4E0A\u6539\u53D8\u4E86\u7F51\u7AD9\u7684\u67B6\u6784\u5F62\u5F0F\uFF0C\u5E26\u6765\u53EF\u6269\u5C55\u6027\u4FBF\u5229\u7684\u540C\u65F6\uFF0C\u8FD8\u5E26\u6765\u4E86\u5F88\u591A\u5176\u4ED6\u4F18\u79C0\u7684\u7279\u6027\u3002\u5728\u5FAE\u670D\u52A1\u67B6\u6784\u4E0B\uFF0C\u4E00\u4E2A\u5927\u578B\u590D\u6742\u8F6F\u4EF6\u7CFB\u7EDF\u4E0D\u518D\u7531\u4E00\u4E2A\u5355\u4F53\u7EC4\u6210\uFF0C\u800C\u662F\u7531\u4E00\u7CFB\u5217\u7684\u5FAE\u670D\u52A1\u7EC4\u6210\u3002\u5176\u4E2D\u6BCF\u4E2A\u5FAE\u670D\u52A1\u53EF\u88AB\u72EC\u7ACB\u5F00\u53D1\u548C\u90E8\u7F72\uFF0C\u5404\u4E2A\u5FAE\u670D\u52A1\u4E4B\u95F4\u662F\u677E\u8026\u5408\u7684\u3002\u6BCF\u4E2A\u5FAE\u670D\u52A1\u4EC5\u4E13\u6CE8\u4E8E\u5B8C\u6210\u4E00\u4EF6\u4EFB\u52A1\uFF0C\u5E76\u8981\u5F88\u597D\u5730\u5B8C\u6210\u8BE5\u4EFB\u52A1\u3002</p><p>\u5728\u5FAE\u670D\u52A1\u67B6\u6784\u4E0B\uFF0C\u5F53\u7F51\u7AD9\u9700\u8981\u589E\u52A0\u65B0\u529F\u80FD\u65F6\uFF0C\u6211\u4EEC\u9664\u4E86\u53EF\u4EE5\u6DFB\u52A0\u65B0\u7684\u4E1A\u52A1\u903B\u8F91\u5916\uFF0C\u8FD8\u53EF\u4EE5\u5229\u7528\u539F\u672C\u5DF2\u7ECF\u5B58\u5728\u7684\u5FAE\u670D\u52A1\u6765\u6784\u5EFA\u65B0\u7684\u529F\u80FD\u3002\u7531\u4E8E\u670D\u52A1\u548C\u670D\u52A1\u4E4B\u95F4\u662F\u76F8\u4E92\u9694\u79BB\u7684\uFF0C\u5E76\u4E14\u5355\u4E2A\u670D\u52A1\u8FD8\u53EF\u4EE5\u88AB\u5176\u4ED6\u591A\u4E2A\u670D\u52A1\u590D\u7528\uFF0C\u6240\u4EE5\u7CFB\u7EDF\u7684\u53EF\u6269\u5C55\u6027\u4F1A\u6BD4\u8F83\u597D\u3002</p><p>\u800C\u5173\u4E8E\u5FAE\u670D\u52A1\u67B6\u6784\u4E0B\uFF0C\u6D4B\u8BD5\u4EBA\u5458\u5E94\u8BE5\u5173\u6CE8\u7684\u6D4B\u8BD5\u70B9\uFF0C\u5EFA\u8BAE\u4F60\u53C2\u8003\u4E13\u680F\u7684\u7B2C 24 \u7BC7\u6587\u7AE0\u300A\u7D27\u8DDF\u65F6\u4EE3\u6B65\u4F10\uFF1A\u5FAE\u670D\u52A1\u6A21\u5F0F\u4E0B API \u6D4B\u8BD5\u8981\u600E\u4E48\u505A\uFF1F\u300B\u4E2D\u7684\u76F8\u5173\u5185\u5BB9\u3002\u5982\u679C\u8FD8\u6709\u54EA\u4E9B\u4E0D\u6E05\u695A\u7684\uFF0C\u4F60\u53EF\u4EE5\u518D\u81EA\u884C\u67E5\u627E\u66F4\u591A\u7684\u76F8\u5173\u8D44\u6599\uFF0C\u6216\u8005\u7ED9\u6211\u7559\u8A00\u4E00\u8D77\u8BA8\u8BBA\u3002</p><p>\u6240\u4EE5\uFF0C\u5728\u4ECA\u5929\u8FD9\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4F1A\u548C\u4F60\u91CD\u70B9\u5206\u4EAB\u4E8B\u4EF6\u9A71\u52A8\u67B6\u6784\u662F\u5982\u4F55\u63D0\u5347\u7F51\u7AD9\u7684\u53EF\u6269\u5C55\u6027\u7684\u3002</p><p>\u800C\u4E8B\u4EF6\u9A71\u52A8\u67B6\u6784\u7684\u843D\u5730\u9760\u7684\u662F\u6D88\u606F\u961F\u5217\uFF0C\u6240\u4EE5\u6211\u4F1A\u540C\u65F6\u548C\u4F60\u5206\u4EAB\u6D88\u606F\u961F\u5217\u7684\u5185\u5BB9\u3002\u6700\u540E\uFF0C\u6211\u4F1A\u518D\u548C\u4F60\u5206\u4EAB\u5F15\u5165\u4E86\u6D88\u606F\u961F\u5217\u540E\uFF0C\u4ECE\u6D4B\u8BD5\u4EBA\u5458\u7684\u89D2\u5EA6\u6765\u770B\u4F1A\u6709\u54EA\u4E9B\u9700\u8981\u989D\u5916\u5173\u6CE8\u7684\u70B9\u3002</p><p><strong>\u4E8B\u4EF6\u9A71\u52A8\u67B6\u6784\u4E0E\u6D88\u606F\u961F\u5217</strong></p><p>\u4E8B\u4EF6\u9A71\u52A8\u67B6\u6784\u8BBE\u8BA1\u7684\u51FA\u53D1\u70B9\u6E90\u4E8E\u8FD9\u6837\u4E00\u4E2A\u4E8B\u5B9E\uFF1A\u5982\u679C\u7CFB\u7EDF\u7684\u5404\u4E2A\u6A21\u5757\u4E4B\u95F4\u7684\u534F\u4F5C\u4E0D\u662F\u901A\u8FC7\u76F4\u63A5\u7684\u8C03\u7528\u5173\u7CFB\u6765\u5B9E\u73B0\u7684\uFF0C\u90A3\u4E48\u7CFB\u7EDF\u7684\u53EF\u6269\u5C55\u6027\u5C31\u4E00\u5B9A\u4F1A\u66F4\u597D\u3002\u95EE\u9898\u662F\uFF0C\u7CFB\u7EDF\u7684\u5404\u4E2A\u6A21\u5757\u95F4\u7684\u534F\u4F5C\u5982\u4F55\u624D\u80FD\u4E0D\u57FA\u4E8E\u8C03\u7528\u5173\u7CFB\u5462\uFF1F</p><p>\u7B54\u6848\u5C31\u662F\u4E8B\u4EF6\u6D88\u606F\u3002\u7CFB\u7EDF\u5404\u4E2A\u6A21\u5757\u4E4B\u95F4\u53EA\u662F\u901A\u8FC7\u6D88\u606F\u961F\u5217\u6765\u4F20\u8F93\u4E8B\u4EF6\u6D88\u606F\uFF0C\u800C\u5404\u6A21\u5757\u4E4B\u95F4\u5E76\u6CA1\u6709\u76F4\u63A5\u7684\u8C03\u7528\u5173\u7CFB\u3001\u4FDD\u6301\u677E\u6563\u7684\u8026\u5408\u5173\u7CFB\u3002</p><p><strong>\u4E8B\u4EF6\u9A71\u52A8\u67B6\u6784\u6700\u5178\u578B\u7684\u4E00\u4E2A\u5E94\u7528\u5C31\u662F\u64CD\u4F5C\u7CFB\u7EDF\u4E2D\u5E38\u89C1\u7684\u751F\u4EA7\u8005\u548C\u6D88\u8D39\u8005\u6A21\u5F0F\uFF0C\u5C06\u5176\u5E94\u7528\u5230\u7F51\u7AD9\u8BBE\u8BA1\u4E2D\u5C31\u662F\u5206\u5E03\u5F0F\u6D88\u606F\u961F\u5217\u3002</strong></p><p>\u5206\u5E03\u5F0F\u6D88\u606F\u961F\u5217\u540C\u6837\u91C7\u7528\u4E86\u751F\u4EA7\u8005\u548C\u6D88\u8D39\u8005\u6A21\u5F0F\uFF1A</p><p>\u6D88\u606F\u7684\u53D1\u9001\u8005\u8D1F\u8D23\u5C06\u6D88\u606F\u53D1\u5E03\u5230\u6D88\u606F\u961F\u5217\u4E2D\uFF0C\u4E5F\u5C31\u662F\u201C\u751F\u4EA7\u8005\u201D\uFF1B \u53E6\u5916\uFF0C\u7CFB\u7EDF\u4E2D\u4F1A\u6709\u4E00\u4E2A\u6216\u8005\u591A\u4E2A\u6D88\u606F\u63A5\u6536\u8005\u8BA2\u9605\u6D88\u606F\uFF0C\u8BA2\u9605\u76EE\u7684\u662F\u4E3A\u4E86\u83B7\u53D6\u6D88\u606F\u5E76\u8FDB\u884C\u5904\u7406\uFF0C\u8FD9\u91CC\u7684\u6D88\u606F\u8BA2\u9605\u8005\u5176\u5B9E\u5C31\u662F\u201C\u6D88\u8D39\u8005\u201D\u3002\u6D88\u606F\u63A5\u6536\u8005\u53D1\u73B0\u6D88\u606F\u961F\u5217\u4E2D\u6709\u65B0\u7684\u6D88\u606F\u540E\uFF0C\u5C31\u4F1A\u7ACB\u9A6C\u5BF9\u5176\u8FDB\u884C\u5904\u7406\u3002 \u53EF\u4EE5\u770B\u5230\uFF0C\u5728\u8FD9\u79CD\u6A21\u5F0F\u4E0B\uFF0C\u6D88\u606F\u7684\u53D1\u9001\u8005\u548C\u63A5\u6536\u8005\u4E4B\u95F4\u5E76\u6CA1\u6709\u4EFB\u4F55\u76F4\u63A5\u7684\u8054\u7CFB\uFF0C\u662F\u677E\u8026\u5408\u7684\u3002\u5B83\u4EEC\u7684\u534F\u4F5C\u662F\u901A\u8FC7\u6D88\u606F\u961F\u5217\u8FD9\u4E2A\u201C\u4E2D\u95F4\u4EBA\u201D\u8FDB\u884C\u7684\u3002\u6D88\u606F\u7684\u53D1\u9001\u8005\u5C06\u6D88\u606F\u53D1\u9001\u81F3\u6D88\u606F\u961F\u5217\u540E\uFF0C\u5C31\u7ED3\u675F\u4E86\u5BF9\u6D88\u606F\u7684\u5904\u7406\uFF0C\u800C\u6D88\u606F\u7684\u63A5\u6536\u8005\u53EA\u662F\u4ECE\u6D88\u606F\u961F\u5217\u4E2D\u83B7\u53D6\u6D88\u606F\u8FDB\u884C\u540E\u7EED\u7684\u5904\u7406\uFF0C\u5E76\u4E0D\u9700\u8981\u77E5\u9053\u8FD9\u4E9B\u6D88\u606F\u4ECE\u54EA\u91CC\u6765\uFF0C\u56E0\u6B64\u53EF\u4EE5\u5F88\u65B9\u4FBF\u5730\u5B9E\u73B0\u9AD8\u53EF\u6269\u5C55\u6027\u3002</p><p>\u6240\u4EE5\uFF0C\u91C7\u7528\u8FD9\u79CD\u6A21\u5F0F\u7684\u8BDD\uFF0C\u5F53\u7F51\u7AD9\u9700\u8981\u589E\u52A0\u65B0\u529F\u80FD\u7684\u65F6\u5019\uFF0C\u53EA\u8981\u589E\u52A0\u5BF9\u5E94\u7684\u65B0\u6A21\u5757\uFF0C\u518D\u7531\u5BF9\u6B64\u6A21\u5757\u611F\u5174\u8DA3\u7684\u201C\u6D88\u8D39\u8005\u201D\u8FDB\u884C\u8BA2\u9605\uFF0C\u5C31\u53EF\u4EE5\u5B9E\u73B0\u5BF9\u539F\u6709\u7CFB\u7EDF\u529F\u80FD\u7684\u6269\u5C55\u4E86\uFF0C\u800C\u5BF9\u539F\u672C\u7684\u7CFB\u7EDF\u6A21\u5757\u672C\u8EAB\u5E76\u6CA1\u6709\u5F71\u54CD\u3002</p><p>\u6B64\u65F6\uFF0C\u6D88\u606F\u961F\u5217\u7684\u67B6\u6784\u5982\u56FE 1 \u6240\u793A\u3002</p><p><img src="https://static001.geekbang.org/resource/image/13/93/13baedfd3f262c91ea8875b4d0080793.png" alt="\u6D88\u606F\u961F\u5217\u7684\u539F\u7406\u56FE"></p><p>\u5F15\u5165\u4E86\u6D88\u606F\u961F\u5217\u540E\uFF0C\u6211\u4EEC\u4E0D\u4EC5\u53EF\u4EE5\u63D0\u9AD8\u7CFB\u7EDF\u7684\u53EF\u6269\u5C55\u6027\uFF0C\u8FD8\u53EF\u4EE5\u518D\u4E00\u5B9A\u7A0B\u5EA6\u4E0A\u6539\u5584\u7F51\u7AD9\u67B6\u6784\u7684\u9AD8\u6027\u80FD\u3001\u9AD8\u53EF\u7528\u6027\u548C\u53EF\u4F38\u7F29\u6027\u3002</p><ul><li>\u4ECE\u6027\u80FD\u65B9\u9762\u6765\u770B\uFF0C\u6D88\u606F\u53D1\u9001\u8005\u4E0D\u9700\u8981\u7B49\u63A5\u6536\u8005\u5B9E\u9645\u5904\u7406\u5B8C\u6210\u540E\u624D\u8FD4\u56DE\uFF0C\u4E5F\u5C31\u662F\u4ECE\u539F\u672C\u7684\u540C\u6B65\u5904\u7406\u53D8\u6210\u4E86\u5F02\u6B65\u5904\u7406\uFF0C\u6240\u4EE5\u7528\u6237\u4F1A\u611F\u77E5\u5230\u7F51\u7AD9\u6027\u80FD\u7684\u63D0\u5347\u3002</li><li>\u4ECE\u9AD8\u53EF\u7528\u65B9\u9762\u6765\u770B\uFF0C\u5047\u5982\u6D88\u606F\u7684\u63A5\u6536\u8005\u6A21\u5757\u53D1\u751F\u4E86\u77ED\u65F6\u95F4\u7684\u6545\u969C\uFF0C\u6B64\u65F6\u5E76\u4E0D\u4F1A\u5F71\u54CD\u6D88\u606F\u53D1\u9001\u8005\u5411\u6D88\u606F\u961F\u5217\u4E2D\u53D1\u9001\u6D88\u606F\uFF0C\u7B49\u5230\u6D88\u606F\u63A5\u6536\u8005\u6A21\u5757\u6062\u590D\u540E\u53EF\u4EE5\u7EE7\u7EED\u540E\u7EED\u7684\u5904\u7406\uFF0C\u53EA\u8981\u8FD9\u6BB5\u65F6\u95F4\u5185\u6D88\u606F\u961F\u5217\u672C\u8EAB\u6CA1\u6709\u88AB\u585E\u6EE1\u800C\u51FA\u73B0\u6D88\u606F\u4E22\u5931\u7684\u60C5\u51B5\u3002\u4ECE\u6574\u4F53\u89D2\u5EA6\u770B\uFF0C\u7CFB\u7EDF\u5E76\u4E0D\u4F1A\u611F\u77E5\u5230\u6D88\u606F\u63A5\u6536\u8005\u6A21\u5757\u66FE\u7ECF\u53D1\u751F\u8FC7\u77ED\u6682\u6545\u969C\uFF0C\u4E5F\u5C31\u76F8\u5F53\u4E8E\u4FDD\u8BC1\u4E86\u7CFB\u7EDF\u7684\u9AD8\u53EF\u7528\u3002</li><li>\u4ECE\u53EF\u4F38\u7F29\u6027\u65B9\u9762\u6765\u770B\uFF0C\u6D88\u606F\u961F\u5217\u7684\u6838\u5FC3\u5176\u5B9E\u5C31\u662F\u4E00\u4E2A\u65E0\u72B6\u6001\u7684\u5B58\u50A8\u3002\u6240\u4EE5\uFF0C\u5F53\u7CFB\u7EDF\u9700\u8981\u80FD\u591F\u4FDD\u7559\u66F4\u591A\u7684\u6D88\u606F\u65F6\uFF0C\u6211\u4EEC\u901A\u8FC7\u7B80\u5355\u5730\u589E\u52A0\u5B58\u50A8\u7A7A\u95F4\u5C31\u53EF\u4EE5\u5B9E\u73B0\u3002\u5C24\u5176\u662F\uFF0C\u5927\u89C4\u6A21\u7684\u7535\u5546\u7F51\u7AD9\u6765\u66F4\u4F1A\u5C06\u6D88\u606F\u961F\u5217\u6269\u5C55\u6210\u4E3A\u5206\u5E03\u5F0F\u6D88\u606F\u961F\u5217\u96C6\u7FA4\uFF0C\u6765\u5B9E\u73B0\u6D88\u606F\u961F\u5217\u7684\u53EF\u4F38\u7F29\u6027\u3002</li></ul><p><strong>\u5F15\u5165\u6D88\u606F\u961F\u5217\u540E\uFF0C\u6D4B\u8BD5\u4EBA\u5458\u9700\u8981\u989D\u5916\u5173\u6CE8\u7684\u70B9</strong></p><p>\u73B0\u5728\uFF0C\u4F60\u5E94\u8BE5\u5DF2\u7ECF\u638C\u63E1\u4E86\u6D88\u606F\u961F\u5217\u7684\u57FA\u672C\u539F\u7406\uFF0C\u4EE5\u53CA\u5728\u7F51\u7AD9\u67B6\u6784\u4E2D\u7684\u7528\u6CD5\u3002\u63A5\u4E0B\u6765\uFF0C\u6211\u4EEC\u518D\u4E00\u8D77\u770B\u770B\u6D88\u606F\u961F\u5217\u5BF9\u6D4B\u8BD5\u7684\u5F71\u54CD\uFF0C\u4EE5\u53CA\u6211\u4EEC\u5728\u6D4B\u8BD5\u65F6\u9700\u8981\u7279\u522B\u5173\u6CE8\u54EA\u4E9B\u70B9\u3002</p><p>\u8FD9\u91CC\uFF0C\u6211\u628A\u6D4B\u8BD5\u4EBA\u5458\u9700\u8981\u989D\u5916\u5173\u6CE8\u7684\u70B9\uFF0C\u5F52\u7EB3\u4E3A\u4E86\u4EE5\u4E0B\u51E0\u70B9\uFF1A</p><ul><li>\u4ECE\u6784\u5EFA\u6D4B\u8BD5\u6570\u636E\u7684\u89D2\u5EA6\u6765\u770B\uFF0C\u4E3A\u4E86\u4EE5\u89E3\u8026\u7684\u65B9\u5F0F\u6D4B\u8BD5\u7CFB\u7EDF\u7684\u5404\u4E2A\u6A21\u5757\uFF0C\u6211\u4EEC\u5C31\u9700\u8981\u5728\u6D88\u606F\u961F\u5217\u4E2D\u6784\u9020\u6D4B\u8BD5\u6570\u636E\u3002\u8FD9\u4E5F\u662F\u4E3A\u4EC0\u4E48\u5F88\u591A\u4E92\u8054\u7F51\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u4E2D\u90FD\u4F1A\u96C6\u6210\u6709\u6D88\u606F\u961F\u5217\u5199\u5165\u5DE5\u5177\u7684\u4E3B\u8981\u539F\u56E0\u3002</li><li>\u4ECE\u6D4B\u8BD5\u9A8C\u8BC1\u7684\u89D2\u5EA6\u6765\u770B\uFF0C\u6211\u4EEC\u4E0D\u4EC5\u9700\u8981\u9A8C\u8BC1\u6A21\u5757\u7684\u884C\u4E3A\uFF0C\u8FD8\u8981\u9A8C\u8BC1\u6A21\u5757\u5728\u6D88\u606F\u961F\u5217\u4E2D\u7684\u8F93\u51FA\u662F\u5426\u7B26\u5408\u9884\u671F\u3002\u4E3A\u6B64\uFF0C\u4E92\u8054\u7F51\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u4E2D\u4E5F\u90FD\u4F1A\u96C6\u6210\u6D88\u606F\u961F\u5217\u7684\u8BFB\u53D6\u5DE5\u5177\u3002</li><li>\u4ECE\u6D4B\u8BD5\u8BBE\u8BA1\u7684\u89D2\u5EA6\u6765\u770B\uFF0C\u6211\u4EEC\u9700\u8981\u8003\u8651\u6D88\u606F\u961F\u5217\u6EE1\u3001\u6D88\u606F\u961F\u5217\u6269\u5BB9\u7B49\u60C5\u51B5\u4E0B\u7CFB\u7EDF\u529F\u80FD\u662F\u5426\u7B26\u5408\u8BBE\u8BA1\u9884\u671F\u3002</li><li>\u9664\u6B64\u4E4B\u5916\uFF0C\u6211\u4EEC\u8FD8\u9700\u8981\u8003\u8651\uFF0C\u67D0\u53F0\u6D88\u606F\u961F\u5217\u670D\u52A1\u5668\u5B95\u673A\u7684\u60C5\u51B5\u4E0B\uFF0C\u4E22\u5931\u6D88\u606F\u7684\u53EF\u6062\u590D\u6027\u4EE5\u53CA\u65B0\u7684\u6D88\u606F\u4E0D\u4F1A\u7EE7\u7EED\u53D1\u5F80\u5B95\u673A\u7684\u670D\u52A1\u5668\u7B49\u7B49\u3002</li></ul><p><strong>\u603B\u7ED3</strong></p><p>\u5728\u4ECA\u5929\u8FD9\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u7F51\u7AD9\u67B6\u6784\u77E5\u8BC6\u4E2D\u7684\u6700\u540E\u4E00\u4E2A\u5185\u5BB9\uFF1A\u53EF\u6269\u5C55\u6027\u3002</p><p>\u53EF\u6269\u5C55\u6027\u6307\u7684\u662F\u7F51\u7AD9\u7684\u67B6\u6784\u8BBE\u8BA1\u80FD\u591F\u5FEB\u901F\u9002\u5E94\u9700\u6C42\u7684\u53D8\u5316\uFF0C\u5F53\u9700\u8981\u589E\u52A0\u65B0\u529F\u80FD\u65F6\uFF0C\u6211\u4EEC\u53EA\u8981\u5BF9\u539F\u6709\u67B6\u6784\u8FDB\u884C\u5C11\u91CF\u4FEE\u6539\uFF0C\u751A\u81F3\u4E0D\u7528\u4FEE\u6539\u5C31\u80FD\u5FEB\u901F\u5B9E\u73B0\u65B0\u7684\u4E1A\u52A1\u9700\u6C42\u3002</p><p>\u4ECE\u6280\u672F\u5B9E\u73B0\u4E0A\u6765\u770B\uFF0C\u6D88\u606F\u961F\u5217\u662F\u5B9E\u73B0\u53EF\u6269\u5C55\u6027\u7684\u91CD\u8981\u6280\u672F\u624B\u6BB5\u4E4B\u4E00\u3002\u5176\u57FA\u672C\u6838\u5FC3\u539F\u7406\u662F\u5404\u6A21\u5757\u4E4B\u95F4\u4E0D\u5B58\u5728\u76F4\u63A5\u7684\u8C03\u7528\u5173\u7CFB\uFF0C\u800C\u662F\u4F7F\u7528\u6D88\u606F\u961F\u5217\uFF0C\u901A\u8FC7\u751F\u4EA7\u8005\u548C\u6D88\u8D39\u8005\u6A21\u5F0F\u6765\u5B9E\u73B0\u6A21\u5757\u95F4\u7684\u534F\u4F5C\uFF0C\u4ECE\u800C\u4FDD\u6301\u6A21\u5757\u4E0E\u6A21\u5757\u95F4\u7684\u677E\u8026\u5408\u5173\u7CFB\u3002</p><p>\u5F15\u5165\u6D88\u606F\u961F\u5217\u540E\uFF0C\u6D4B\u8BD5\u6570\u636E\u7684\u521B\u5EFA\u548C\u6D4B\u8BD5\u7ED3\u679C\u7684\u9A8C\u8BC1\u5DE5\u4F5C\uFF0C\u90FD\u9700\u8981\u901A\u8FC7\u8BFB\u5199\u6D88\u606F\u961F\u5217\u6765\u5B8C\u6210\u3002\u540C\u65F6\uFF0C\u6211\u4EEC\u8FD8\u8981\u8003\u8651\u5230\u6D88\u606F\u961F\u5217\u6EE1\u3001\u6D88\u606F\u961F\u5217\u6269\u5BB9\uFF0C\u4EE5\u53CA\u6D88\u606F\u961F\u5217\u670D\u52A1\u5668\u5B95\u673A\u60C5\u51B5\u4E0B\u7684\u7CFB\u7EDF\u529F\u80FD\u9A8C\u8BC1\u3002\u8FD9\u51E0\u4E2A\u70B9\uFF0C\u5C31\u662F\u6D4B\u8BD5\u4EBA\u5458\u9700\u8981\u989D\u5916\u5173\u6CE8\u7684\u70B9\u4E86\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u4F60\u5728\u5B9E\u9645\u5DE5\u4F5C\u4E2D\u63A5\u89E6\u8FC7\u54EA\u4E9B\u79CD\u7C7B\u7684\u6D88\u606F\u961F\u5217\uFF1F\u5728\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\uFF0C\u662F\u5426\u9047\u5230\u8FC7\u548C\u6D88\u606F\u961F\u5217\u6709\u5173\u7684\u7F3A\u9677\u5462\uFF1F</p>',45);function i(n,e){return s}var l=p(r,[["render",i],["__file","52.html.vue"]]);export{l as default};
